Single.Single:
// PROGRAM PLC_PRG_MAIN

// 0. DIAGNOSTIC CAN (Joystick)
// TODO: Wire CanOnline/CanOperational from CAN task
InstanceDiagCan(
    Enable := TRUE,
    Reset := FALSE,
    CanOnline := TRUE,         // TBD: from CAN task
    CanOperational := TRUE     // TBD: from CAN task
);

// 0. DIAGNOSTIC ETHERCAT (Variateur, EncoderM1, EncoderM2)
// TODO: Wire WcState/SlaveState from EtherCAT task
InstanceDiagEthercat(
    Enable := TRUE,
    Reset := FALSE,
    VariateurWcState := FALSE,         // TBD: from EtherCAT master
    VariateurSlaveState := 8,          // TBD: from EtherCAT master
    EncoderM1WcState := FALSE,         // TBD: from EtherCAT master
    EncoderM1SlaveState := 8,          // TBD: from EtherCAT master
    EncoderM2WcState := FALSE,         // TBD: from EtherCAT master
    EncoderM2SlaveState := 8           // TBD: from EtherCAT master
);

// Update local status
LocalEthercatOk := InstanceDiagEthercat.Variateur.Operational AND InstanceDiagEthercat.EncoderM1.Operational AND InstanceDiagEthercat.EncoderM2.Operational;

// 1. ÉVALUATION DE LA SÉCURITÉ TRANSVERSE
InstanceSafety(
    Enable := TRUE,
    EStopArmed := LocalEmergencyStopTOR,
    CanOnline := InstanceDiagCan.Joystick.Online,
    CanOperational := InstanceDiagCan.Joystick.Operational,
    EthercatOk := LocalEthercatOk
);

// 2. ACQUISITION DU GESTE OPÉRATEUR SÉCURISÉ
InstanceJoystick(
    Enable := TRUE,
    SafeStop := InstanceSafety.SafeStop,   // Reçoit la sécurité positive inversée
    SafetyOk := InstanceSafety.SafetyOk,   // Reçoit le feu vert global
    CanOnline := InstanceDiagCan.Joystick.Online,
    CanOperational := InstanceDiagCan.Joystick.Operational,
    RawX := JoyXRaw_ANA1,
    RawY := JoyYRaw_ANA2,
    RawButton := JoyBtnRaw
);

PROGRAM PLC_PRG_MAIN
VAR
    InstanceSafety      : FB_Safety;
    InstanceJoystick    : FB_Joystick;
    InstanceDiagCan     : DiagCanOpen;           // Diagnostic CAN/Joystick
    InstanceDiagEthercat : diagETHERCAT;        // Diagnostic EtherCAT (3 devices)

	LocalEmergencyStopTOR  : BOOL := TRUE;
	LocalEthercatOk        : BOOL := FALSE;      // Résumé diagnostic EtherCAT

END_VAR
